mapper.select:
SELECT 
  FROM er.tn_cef_lcyc lc
 WHERE lc.cef_id   = #{cefId}
   AND lc.claim_no = #{claimNo}
   AND NOW() BETWEEN lc.use_bgng_dt AND lc.use_end_dt

mapper.update:
UPDATE er.tn_cef_lcyc
   SET use_end_dt       = NOW() - INTERVAL '1 minute',
       last_chg_dt      = NOW(),
       last_chg_user_id = #{userId}
 WHERE cef_id   = #{cefId}
   AND claim_no = #{claimNo}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt
